    const { rerender } = render(
      <SessionDetail
        session={makeSession({
          id: "worker-live",
          projectId: "my-app",
          status: "working",
          activity: "active",
          pr: null,
        })}
      />,
    );

    expect(screen.getByTestId("direct-terminal")).toHaveTextContent("worker-live");

    rerender(
      <SessionDetail
        session={makeSession({
          id: "worker-live",
          projectId: "my-app",
          status: "terminated",
          activity: "exited",
          pr: null,
        })}
      />,
    );

    expect(screen.getByTestId("direct-terminal")).toHaveTextContent("worker-live");
    expect(screen.queryByText(/Terminal session has ended/i)).not.toBeInTheDocument();
  });
});

