35	export function buildTerminalThemes(variant: TerminalVariant): { dark: ITheme; light: ITheme } {
36	  const agentAccent = {
37	    cursor: "#5b7ef8",
38	    selDark: "rgba(91, 126, 248, 0.30)",
39	    selLight: "rgba(91, 126, 248, 0.25)",
40	  };
41	  const orchAccent = agentAccent;
