48	    cursorAccent: "#0a0a0f",
49	    selectionBackground: accent.selDark,
50	    selectionInactiveBackground: "rgba(128, 128, 128, 0.2)",
51	    // ANSI colors — slightly warmer than pure defaults
52	    black: "#1a1a24",
53	    red: "#ef4444",
54	    green: "#22c55e",
55	    yellow: "#f59e0b",
