98	
99	/**
100	 * Direct xterm.js terminal with native WebSocket connection.
101	 * Implements Extended Device Attributes (XDA) handler to enable
102	 * tmux clipboard support (OSC 52) without requiring iTerm2 attachment.
103	 *
104	 * Based on DeepWiki analysis:
105	 * - tmux queries for XDA (CSI > q / XTVERSION) to detect terminal type
106	 * - When tmux sees "XTerm(" in response, it enables TTYC_MS (clipboard)
107	 * - xterm.js doesn't implement XDA by default, so we register custom handler
108	 */
109	export function DirectTerminal({
110	  sessionId,
111	  startFullscreen = false,
112	  variant = "agent",
113	  appearance = "theme",
114	  height = "max(440px, calc(100dvh - 440px))",
115	  isOpenCodeSession = false,
116	  reloadCommand,
117	  chromeless = false,
118	  onTerminalStateChange,
119	}: DirectTerminalProps) {
120	  const router = useRouter();
121	  const pathname = usePathname();
122	  const searchParams = useSearchParams();
123	  const { resolvedTheme } = useTheme();
124	  const terminalThemes = useMemo(() => buildTerminalThemes(variant), [variant]);
125	  const {
126	    subscribeTerminal,
127	    subscribeTerminalLifecycle,
128	    writeTerminal,
129	    resizeTerminal: resizeTerminalMux,
130	    openTerminal,
131	    closeTerminal,
132	    status: muxStatus,
133	  } = useMux();
134	
135	  const terminalRef = useRef<HTMLDivElement>(null);
136	  const terminalInstance = useRef<TerminalType | null>(null);
137	  const fitAddon = useRef<FitAddonType | null>(null);
138	  const onTerminalStateChangeRef = useRef(onTerminalStateChange);
139	  const muxStatusRef = useRef(muxStatus);
140	  onTerminalStateChangeRef.current = onTerminalStateChange;
141	  muxStatusRef.current = muxStatus;
142	  const [fullscreen, setFullscreen] = useState(startFullscreen);
143	  const [error, setError] = useState<string | null>(null);
144	  const [reloading, setReloading] = useState(false);
145	  const [reloadError, setReloadError] = useState<string | null>(null);
146	
147	  // Update URL when fullscreen changes
148	  useEffect(() => {
149	    const params = new URLSearchParams(searchParams.toString());
150	
151	    if (fullscreen) {
152	      params.set("fullscreen", "true");
153	    } else {
154	      params.delete("fullscreen");
155	    }
156	
157	    const newUrl = params.toString() ? `${pathname}?${params.toString()}` : pathname;
158	    router.replace(newUrl, { scroll: false });
159	  }, [fullscreen, pathname, router, searchParams]);
160	
161	  async function handleReload(): Promise<void> {
162	    if (!isOpenCodeSession || reloading) return;
163	    setReloadError(null);
164	    setReloading(true);
165	    try {
166	      let commandToSend = reloadCommand;
167	
168	      if (!commandToSend) {
169	        const remapRes = await fetch(`/api/sessions/${encodeURIComponent(sessionId)}/remap`, {
170	          method: "POST",
171	        });
172	        if (!remapRes.ok) {
173	          throw new Error(`Failed to remap OpenCode session: ${remapRes.status}`);
174	        }
175	        const remapData = (await remapRes.json()) as { opencodeSessionId?: unknown };
176	        if (
177	          typeof remapData.opencodeSessionId !== "string" ||
178	          remapData.opencodeSessionId.length === 0
179	        ) {
180	          throw new Error("Missing OpenCode session id after remap");
181	        }
182	        commandToSend = `/exit\nopencode --session ${remapData.opencodeSessionId}\n`;
183	      }
184	
185	      const sendRes = await fetch(`/api/sessions/${encodeURIComponent(sessionId)}/send`, {
186	        method: "POST",
187	        headers: { "Content-Type": "application/json" },
188	        body: JSON.stringify({ message: commandToSend }),
189	      });
190	      if (!sendRes.ok) {
191	        throw new Error(`Failed to send reload command: ${sendRes.status}`);
192	      }
193	    } catch (err) {
194	      setReloadError(err instanceof Error ? err.message : "Failed to reload OpenCode session");
195	    } finally {
196	      setReloading(false);
197	    }
198	  }
199	
200	  useEffect(() => {
201	    if (!terminalRef.current) return;
202	
203	    // Dynamically import xterm.js to avoid SSR issues
204	    let mounted = true;
205	    let cleanup: (() => void) | null = null;
206	    let inputDisposable: { dispose(): void } | null = null;
207	    let unsubscribe: (() => void) | null = null;
208	    let unsubscribeLifecycle: (() => void) | null = null;
209	
210	    Promise.all([
211	      import("xterm").then((mod) => mod.Terminal),
212	      import("@xterm/addon-fit").then((mod) => mod.FitAddon),
213	      import("@xterm/addon-web-links").then((mod) => mod.WebLinksAddon),
214	      document.fonts.ready,
215	    ])
216	      .then(([Terminal, FitAddon, WebLinksAddon]) => {
217	        if (!mounted || !terminalRef.current) return;
218	
219	        const isDark = appearance === "dark" || resolvedTheme !== "light";
220	        const activeTheme = isDark ? terminalThemes.dark : terminalThemes.light;
221	
222	        // Initialize xterm.js Terminal
223	        const terminal = new Terminal({
224	          cursorBlink: true,
225	          fontSize: 13,
226	          fontFamily:
227	            'var(--font-jetbrains-mono), "JetBrains Mono", "SF Mono", Menlo, Monaco, "Courier New", monospace',
228	          theme: activeTheme,
229	          // Light mode needs an explicit contrast floor because agent UIs often emit
230	          // dim/faint ANSI sequences that become unreadable on a near-white background.
231	          minimumContrastRatio: isDark ? 1 : 7,
232	          scrollback: 10000,
233	          allowProposedApi: true,
234	          fastScrollModifier: "alt",
235	          fastScrollSensitivity: 3,
236	          scrollSensitivity: 1,
237	        });
238	
239	        // Add FitAddon for responsive sizing
240	        const fit = new FitAddon();
241	        terminal.loadAddon(fit);
242	        fitAddon.current = fit;
243	
244	        // Add WebLinksAddon for clickable links
245	        const webLinks = new WebLinksAddon();
246	        terminal.loadAddon(webLinks);
247	
248	        // **CRITICAL FIX**: Register XDA (Extended Device Attributes) handler
249	        // This makes tmux recognize our terminal and enable clipboard support
250	        terminal.parser.registerCsiHandler(
251	          { prefix: ">", final: "q" }, // CSI > q is XTVERSION / XDA
252	          () => {
253	            // Respond with XTerm identification that tmux recognizes
254	            // tmux looks for "XTerm(" in the response (see tmux tty-keys.c)
255	            // Format: DCS > | XTerm(version) ST
256	            // DCS = \x1bP, ST = \x1b\\
257	            terminal.write("\x1bP>|XTerm(370)\x1b\\");
258	            console.log("[DirectTerminal] Sent XDA response for clipboard support");
259	            return true; // Handled
260	          },
261	        );
262	
263	        // Register OSC 52 handler for clipboard support
264	        // tmux sends OSC 52 with base64-encoded text when copying
265	        terminal.parser.registerOscHandler(52, (data) => {
266	          const parts = data.split(";");
267	          if (parts.length < 2) return false;
268	          const b64 = parts[parts.length - 1];
269	          try {
270	            // Decode base64 → binary string → Uint8Array → UTF-8 text
271	            // atob() alone only handles Latin-1; TextDecoder is needed for UTF-8
272	            const binary = atob(b64);
273	            const bytes = Uint8Array.from(binary, (c) => c.charCodeAt(0));
274	            const text = new TextDecoder().decode(bytes);
275	            navigator.clipboard?.writeText(text).catch(() => {});
276	          } catch {
277	            // Ignore decode errors
278	          }
279	          return true;
280	        });
281	
282	        // Open terminal in DOM
283	        terminal.open(terminalRef.current);
284	        terminalInstance.current = terminal;
285	
286	        // Fit terminal to container
287	        fit.fit();
288	
289	        // ── Preserve selection while terminal receives output ────────
290	        // xterm.js clears the selection on every terminal.write(). We
291	        // buffer incoming data while a selection is active so the
292	        // highlight stays visible for Cmd+C. The buffer is flushed
293	        // when the selection is cleared (click, keypress, etc.).
294	        const writeBuffer: string[] = [];
295	        let selectionActive = false;
296	        let safetyTimer: ReturnType<typeof setTimeout> | null = null;
297	        let bufferBytes = 0;
298	        const MAX_BUFFER_BYTES = 1_048_576; // 1 MB
299	
300	        const flushWriteBuffer = () => {
301	          if (safetyTimer) {
302	            clearTimeout(safetyTimer);
303	            safetyTimer = null;
304	          }
305	          if (writeBuffer.length > 0) {
306	            terminal.write(writeBuffer.join(""));
307	            writeBuffer.length = 0;
308	            bufferBytes = 0;
309	          }
310	        };
311	
312	        const selectionDisposable = terminal.onSelectionChange(() => {
313	          if (terminal.hasSelection()) {
314	            selectionActive = true;
315	            // Safety: flush after 5s to prevent unbounded buffering
316	            if (!safetyTimer) {
317	              safetyTimer = setTimeout(() => {
318	                selectionActive = false;
319	                flushWriteBuffer();
320	              }, 5_000);
321	            }
322	          } else {
323	            selectionActive = false;
324	            flushWriteBuffer();
325	          }
326	        });
327	
328	        // Intercept Cmd+C (Mac) and Ctrl+Shift+C (Linux/Win) for copy.
329	        // Paste (Cmd+V / Ctrl+Shift+V) is handled natively by xterm.js
330	        // via its internal textarea — no custom handler needed.
331	        terminal.attachCustomKeyEventHandler((e: KeyboardEvent) => {
332	          if (e.type !== "keydown") return true;
333	
334	          // Cmd+C / Ctrl+Shift+C — copy selection
335	          const isCopy =
336	            (e.metaKey && !e.ctrlKey && !e.altKey && e.code === "KeyC") ||
337	            (e.ctrlKey && e.shiftKey && e.code === "KeyC");
338	          if (isCopy && terminal.hasSelection()) {
339	            navigator.clipboard?.writeText(terminal.getSelection()).catch(() => {});
340	            // Clear selection so the terminal resumes receiving output
341	            terminal.clearSelection();
342	            return false;
343	          }
344	
345	          return true;
346	        });
347	
348	        // Open terminal via mux
349	        unsubscribeLifecycle = subscribeTerminalLifecycle(sessionId, (event) => {
350	          onTerminalStateChangeRef.current?.(event);
351	          if (event.type === "error") {
352	            setError(event.message);
353	          }
354	        });
355	
356	        // Open terminal via mux
357	        openTerminal(sessionId);
358	
359	        // Subscribe to terminal data via mux
360	        unsubscribe = subscribeTerminal(sessionId, (data) => {
361	          if (selectionActive) {
362	            writeBuffer.push(data);
363	            bufferBytes += data.length;
364	            // Flush if buffer exceeds 1 MB to prevent OOM
365	            if (bufferBytes > MAX_BUFFER_BYTES) {
366	              selectionActive = false;
367	              flushWriteBuffer();
368	            }
369	          } else {
370	            terminal.write(data);
371	          }
372	        });
373	
374	        // Handle window resize
375	        const handleResize = () => {
376	          if (fit) {
377	            fit.fit();
378	            resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
379	          }
380	        };
381	
382	        window.addEventListener("resize", handleResize);
383	
384	        // Terminal input → mux
385	        inputDisposable = terminal.onData((data) => {
386	          writeTerminal(sessionId, data);
387	        });
388	
389	        // Send initial size
390	        resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
391	
392	        // Store cleanup function to be called from useEffect cleanup
393	        cleanup = () => {
394	          selectionDisposable.dispose();
395	          if (safetyTimer) clearTimeout(safetyTimer);
396	          window.removeEventListener("resize", handleResize);
397	          inputDisposable?.dispose();
398	          inputDisposable = null;
399	          unsubscribe?.();
400	          unsubscribeLifecycle?.();
401	          closeTerminal(sessionId);
402	          terminal.dispose();
403	        };
404	      })
405	      .catch((err) => {
406	        console.error("[DirectTerminal] Failed to load xterm.js:", err);
407	        setError("Failed to load terminal");
408	      });
409	
410	    return () => {
411	      mounted = false;
412	      cleanup?.();
413	    };
414	  }, [
415	    appearance,
416	    sessionId,
417	    variant,
418	    resolvedTheme,
419	    terminalThemes,
420	    subscribeTerminal,
421	    writeTerminal,
422	    resizeTerminalMux,
423	    openTerminal,
424	    closeTerminal,
425	    subscribeTerminalLifecycle,
426	  ]);
427	
428	  // Re-send terminal dimensions on every reconnect so the server-side PTY
429	  // matches the client's xterm.js size (new PTYs spawn at 80×24 default).
430	  useEffect(() => {
431	    if (muxStatus !== "connected") return;
432	    const fit = fitAddon.current;
433	    const terminal = terminalInstance.current;
434	    if (!fit || !terminal) return;
435	    fit.fit();
436	    resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
437	  }, [muxStatus, sessionId, resizeTerminalMux]);
438	
439	  // Live theme switching without terminal recreation
440	  useEffect(() => {
441	    const terminal = terminalInstance.current;
442	    if (!terminal) return;
443	    const isDark = appearance === "dark" || resolvedTheme !== "light";
444	    terminal.options.theme = isDark ? terminalThemes.dark : terminalThemes.light;
445	    terminal.options.minimumContrastRatio = isDark ? 1 : 7;
446	  }, [appearance, resolvedTheme, terminalThemes]);
447	
448	  // Re-fit terminal when fullscreen changes
449	  useEffect(() => {
450	    const fit = fitAddon.current;
451	    const terminal = terminalInstance.current;
452	    const container = terminalRef.current;
453	
454	    if (!fit || !terminal || muxStatusRef.current !== "connected" || !container) {
455	      return;
456	    }
457	
458	    let resizeAttempts = 0;
459	    const maxAttempts = 60;
460	    let cancelled = false;
461	    let rafId = 0;
462	    let lastHeight = -1;
463	
464	    const resizeTerminal = () => {
465	      if (cancelled) return;
466	      resizeAttempts++;
467	
468	      // Wait for the container height to stabilise (CSS transition finished)
469	      const currentHeight = container.getBoundingClientRect().height;
470	      const settled = lastHeight >= 0 && Math.abs(currentHeight - lastHeight) < 1;
471	      lastHeight = currentHeight;
472	
473	      if (!settled && resizeAttempts < maxAttempts) {
474	        // Container is still transitioning, try again next frame
475	        rafId = requestAnimationFrame(resizeTerminal);
476	        return;
477	      }
478	
479	      // Container is at target size, now resize terminal
480	      terminal.refresh(0, terminal.rows - 1);
481	      fit.fit();
482	      terminal.refresh(0, terminal.rows - 1);
483	
