66	async function loadBuiltinPluginModule(packageName: string): Promise<BuiltinPlugin> {
67	  const packageRoot = resolveBuiltinPackageRoot(packageName);
68	  const packageJson = JSON.parse(
69	    readFileSync(resolvePath(packageRoot, "package.json"), "utf8"),
70	  ) as {
71	    exports?: { ".": { import?: string } };
72	    main?: string;
73	  };
74	  const entry =
75	    packageJson.exports?.["."].import ??
76	    packageJson.main;
77	
78	  if (!entry) {
79	    throw new Error(`No import entry found in ${packageName}/package.json`);
80	  }
81	
82	  const resolvedUrl = pathToFileURL(resolvePath(packageRoot, entry)).href;
83	  return import(/* webpackIgnore: true */ resolvedUrl) as Promise<BuiltinPlugin>;
84	}
