86	function resolveBuiltinPackageRoot(packageName: string): string {
87	  const installedPackageRoot = resolvePath(process.cwd(), "node_modules", ...packageName.split("/"));
88	  if (existsSync(resolvePath(installedPackageRoot, "package.json"))) {
89	    return installedPackageRoot;
90	  }
91	
92	  const workspacePluginName = packageName.replace("@aoagents/ao-plugin-", "");
93	  const monorepoRoot = findMonorepoRoot(process.cwd());
94	  const workspacePackageRoot = resolvePath(monorepoRoot, "packages", "plugins", workspacePluginName);
95	  if (existsSync(resolvePath(workspacePackageRoot, "package.json"))) {
96	    return workspacePackageRoot;
97	  }
98	
99	  throw new Error(
100	    `Could not resolve ${packageName} from ${installedPackageRoot} or ${workspacePackageRoot}`,
101	  );
102	}
