104	function findMonorepoRoot(startDir: string): string {
105	  let currentDir = startDir;
106	
107	  while (true) {
108	    if (existsSync(resolvePath(currentDir, "pnpm-workspace.yaml"))) {
109	      return currentDir;
110	    }
111	
112	    const parentDir = dirname(currentDir);
113	    if (parentDir === currentDir) {
114	      throw new Error(`Could not find monorepo root from ${startDir}`);
115	    }
116	    currentDir = parentDir;
117	  }
118	}
